}

.dial-position {
  position: absolute;
}

.dial-position--top {
  top: 1.75rem;
  left: 50%;
  transform: translateX(-50%);
}

.dial-position--right {
  top: 50%;
  right: 1.75rem;
  transform: translateY(-50%);
}

.dial-position--bottom {
  bottom: 1.75rem;
  left: 50%;
  transform: translateX(-50%);
}

.dial-position--left {
  top: 50%;
  left: 1.75rem;
  transform: translateY(-50%);
}

