import { AerisTreeModule } from '@aeris-ui/core/tree';
import { AerisTreeTableModule, type AerisTreeTableColumn, type AerisTreeTableNode } from '@aeris-ui/core/tree-table';

type FileRecord = AerisTreeTableData & {
